{
  "source": "locked_product_design_baseline",
  "project_name": "Slack Fronting Showcase 0.2.0 RC4",
  "baseline_locked_at": "2026-06-04T21:30:26.115Z",
  "requirements": {
    "id": "req-9afe8f1d-098a-4dd4-a4bd-e42277ea5d72",
    "title": "Drafted Product Requirements",
    "data": {
      "auth": {
        "purpose_binding": true,
        "scoped_authority": true,
        "delegation_tokens": true
      },
      "audit": {
        "durable": true,
        "searchable": true
      },
      "scale": {
        "shape_preference": "production_single_service",
        "high_availability": false
      },
      "trust": {
        "mode": "signed",
        "checkpoints": false
      },
      "system": {
        "name": "slack-fronting-showcase-0-2-0-rc4",
        "domain": "slack",
        "deployment_intent": "public_http_service"
      },
      "lineage": {
        "task_id": true,
        "invocation_id": true,
        "client_reference_id": true,
        "parent_invocation_id": true
      },
      "transports": {
        "grpc": false,
        "http": true,
        "stdio": false
      },
      "permissions": {
        "preflight_discovery": true,
        "restricted_vs_denied": true
      },
      "risk_profile": {},
      "business_constraints": {
        "assistant_drafted_requirements_count": 7,
        "assistant_drafted_requirements_summary": "Expose governed Slack capabilities instead of raw Slack operations: The product shall present business-facing Slack capabilities for bounded channel context, thread inspection, message preparation, incident update preparation, and announcement request flows. It shall not expose raw Slack Web API operations, raw MCP operations, or direct workspace tool access to agents or end users.\nSupport bounded Slack context reads for channels and threads: The product shall allow governed retrieval of recent Slack channel context and thread context using bounded results only. Read flows shall support channel-scoped context lookup and thread summarization without enabling raw workspace export or unrestricted message retrieval.\nPrepare Slack messages and incident updates without sending them: The product shall support preparation of channel messages and structured incident updates as preview-only outputs. These flows shall stop before posting, return draft or preview content for review, and avoid any direct Slack mutation during preparation.\nRequire approval before announcement or posting actions cross into execution: The product shall enforce an approval boundary for announcement-style posting and any other governed posting flow. Before execution, the system shall return an approval-ready request or preview and shall not post to Slack until the required approval condition is satisfied.\nEnforce channel boundaries through allow-list policy: The product shall enforce channel allow-list rules on governed Slack reads, message preparation, incident update preparation, announcement requests, and any eventual posting action. Requests involving unauthorized channels shall be denied with a governed response rather than falling through to raw Slack access.\nRecord audit evidence for governed actions and policy denials: The product shall produce audit evidence for governed Slack reads, preview generation, approval requests, and denied actions. Audit records shall preserve enough traceability for reviewers to understand what capability was invoked, what boundary or policy applied, and why a request was allowed, stopped, or denied.\nExplicitly deny raw export, raw tool access, and unauthorized posting: The product shall explicitly refuse requests for raw Slack API access, raw MCP access, bulk export, and posting to channels outside authorized policy. Denial behavior shall be intentional and user-visible, not an accidental backend failure or silent omission."
      }
    }
  },
  "scenarios": [
    {
      "id": "scn-d52492b8-36bc-4230-9814-c13688290ed1",
      "title": "Review audit evidence for a governed Slack read or preparation flow",
      "data": {
        "scenario": {
          "name": "review-audit-evidence-for-a-governed-slack-read-or-preparation-flow",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Audit evidence is explicit in the project summary and fronting intent, but the exact evidence schema is not defined in the brief.",
            "capability": "slack.announcement.request",
            "confidence": "medium",
            "time_scope": "After a governed request outcome",
            "actor_context": "Reviewer inspecting governed Slack behavior after execution or denial",
            "business_scope": "Auditability of bounded reads, preparation flows, denials, and approval stops"
          },
          "category": "orchestration",
          "narrative": "A reviewer needs to understand how the governed Slack fronting system handled a request. The system provides evidence showing which governed capability ran, whether the flow completed or stopped, and what boundary or approval rule applied.",
          "expected_behavior": [
            "Show whether the flow was a bounded read, preview preparation, denial, or approval stop.",
            "Explain which governed capability handled the request.",
            "Show why the system stopped or allowed the flow at a high level.",
            "Support review without exposing raw Slack credentials or unrestricted tooling."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Preserve auditable runtime evidence for governed Slack interactions.",
            "Make stop conditions and policy outcomes reviewable after the fact.",
            "Keep audit review aligned to governed capabilities rather than raw backend operations."
          ],
          "participating_services": [
            "slack-fronting",
            "slack-governance"
          ]
        }
      }
    },
    {
      "id": "scn-25ec2882-5c68-4945-a8d8-1032ec6d1d7f",
      "title": "Deny agent access to raw Slack API, MCP, or bulk export paths",
      "data": {
        "scenario": {
          "name": "deny-agent-access-to-raw-slack-api-mcp-or-bulk-export-paths",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The fronting intent explicitly calls for denial of raw Slack API, MCP, and bulk export access, but the brief does not define a detailed user-facing denial flow.",
            "capability": "slack.channel.read_context",
            "confidence": "medium",
            "time_scope": "At request time",
            "actor_context": "Agent or user attempting to bypass governed Slack fronting",
            "business_scope": "Explicit denial of raw integration surfaces in favor of governed capabilities"
          },
          "category": "safety",
          "narrative": "An agent tries to bypass governed Slack capabilities by requesting raw Slack API, MCP, or bulk export access. The system refuses the request and directs the actor back to bounded read, summarization, or preparation capabilities.",
          "expected_behavior": [
            "Explicitly deny raw Slack API, MCP, and bulk export access.",
            "Avoid silent fallback to unrestricted tools.",
            "Guide the actor toward approved governed capabilities.",
            "Make the denial auditable."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Represent denied raw-access paths as explicit policy outcomes.",
            "Preserve separation between business capabilities and native integration surfaces.",
            "Support audit evidence that raw access was not exposed."
          ],
          "participating_services": [
            "slack-fronting",
            "slack-governance"
          ]
        }
      }
    },
    {
      "id": "scn-a1b03af6-5cfa-4504-9bbd-cd090ff53a93",
      "title": "Deny reads or message preparation for unauthorized Slack channels",
      "data": {
        "scenario": {
          "name": "deny-reads-or-message-preparation-for-unauthorized-slack-channels",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The fronting intent explicitly requires channel allow-list enforcement and unauthorized channel posting denial, but the evidence does not define the exact allow-list mechanism.",
            "capability": "slack.channel.read_context",
            "confidence": "medium",
            "time_scope": "At request time",
            "actor_context": "Slack requester whose requested channel is outside allowed scope",
            "business_scope": "Channel access governance and unauthorized channel denial"
          },
          "category": "safety",
          "narrative": "A Slack requester attempts to read from or prepare content for a channel that is outside the governed boundary. The system stops the flow, denies the action, and keeps the user within approved channel limits.",
          "expected_behavior": [
            "Reject access to channels outside the governed boundary.",
            "Reject unauthorized posting targets before preview or send paths continue.",
            "Explain that the denial is due to channel governance rather than a generic failure.",
            "Avoid fallback to raw Slack tools."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Make channel-boundary enforcement visible in runtime outcomes.",
            "Support consistent denial behavior across read and write-adjacent flows.",
            "Capture audit evidence for why the channel request was denied."
          ],
          "participating_services": [
            "slack-fronting",
            "slack-governance"
          ]
        }
      }
    },
    {
      "id": "scn-213966f3-0bf8-4ba2-a28e-a5bf4f2b3155",
      "title": "Request a channel announcement that requires approval before posting",
      "data": {
        "scenario": {
          "name": "request-a-channel-announcement-that-requires-approval-before-posting",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the announcement request capability, governance service, and approval-gated posture in both the evidence and fronting intent.",
            "capability": "slack.announcement.request",
            "confidence": "high",
            "time_scope": "Single announcement request",
            "actor_context": "Slack requester initiating an announcement that needs approval",
            "business_scope": "Approval-gated announcement preparation and request handling"
          },
          "category": "cross_service",
          "narrative": "A Slack requester needs to make a broader channel announcement but cannot post directly. The governance path accepts the target channel and announcement content, creates a governed request, and stops until approval is granted.",
          "expected_behavior": [
            "Allow requesters to prepare an announcement without directly posting it.",
            "Stop at an explicit approval boundary.",
            "Keep announcement handling on the governed path rather than raw Slack posting.",
            "Preserve a reviewable artifact for approvers."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Represent approval-gated announcement requests as a separate governed capability.",
            "Surface approval-required as a first-class runtime outcome.",
            "Support audit evidence for request, review, and stop conditions."
          ],
          "participating_services": [
            "slack-governance"
          ]
        }
      }
    },
    {
      "id": "scn-f624ff86-b420-454e-bde5-7fddc3ce822d",
      "title": "Prepare a structured incident update for Slack and stop before posting",
      "data": {
        "scenario": {
          "name": "prepare-a-structured-incident-update-for-slack-and-stop-before-posting",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the incident update preparation capability, required inputs, and prepare-only posture.",
            "capability": "slack.incident_update.prepare",
            "confidence": "high",
            "time_scope": "Per incident status update",
            "actor_context": "Slack requester preparing an operational incident update",
            "business_scope": "Structured incident communication preparation with approval boundary"
          },
          "category": "safety",
          "narrative": "A Slack requester needs to communicate incident status in a governed way. The service prepares a structured incident update preview for a channel using incident-specific fields and stops before any post is made.",
          "expected_behavior": [
            "Require structured incident inputs before preparation.",
            "Constrain status to the supported values.",
            "Return a preview rather than posting the update.",
            "Preserve approval and audit boundaries for operational communications."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Support structured input contracts for incident updates.",
            "Make preview-only and approval-stop behavior explicit.",
            "Record evidence that the incident communication was prepared under governance."
          ],
          "participating_services": [
            "slack-fronting"
          ]
        }
      }
    },
    {
      "id": "scn-34c91767-3a5d-4ab4-97ca-1601e79a7ec3",
      "title": "Read bounded Slack channel context without exposing raw workspace access",
      "data": {
        "scenario": {
          "name": "read-bounded-slack-channel-context-without-exposing-raw-workspace-access",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the read-context capability, the fronting intent for bounded channel reads, and the explicit denial of raw Slack access.",
            "capability": "slack.channel.read_context",
            "confidence": "high",
            "time_scope": "Recent channel context only",
            "actor_context": "Slack requester seeking channel context within governed boundaries",
            "business_scope": "Bounded Slack channel context retrieval with channel boundary enforcement and denial of raw tool access"
          },
          "category": "safety",
          "narrative": "A Slack requester needs recent channel context to understand what is happening in a channel. The governed fronting service reads only bounded recent messages for the declared context and returns a constrained result instead of raw workspace access.",
          "expected_behavior": [
            "Return bounded recent channel context only.",
            "Require a concrete channel reference before reading.",
            "Keep the user within governed Slack capabilities instead of exposing raw Slack tools.",
            "Stop or restrict when the request falls outside approved channel boundaries."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Represent bounded read behavior as an explicit capability contract.",
            "Enforce channel boundary and raw-access denial as visible runtime outcomes.",
            "Preserve auditable evidence that the read stayed within governed scope."
          ],
          "participating_services": [
            "slack-fronting"
          ]
        }
      }
    },
    {
      "id": "scn-02c541d9-3998-4a4a-8893-e95cdf23e5c1",
      "title": "Summarize a Slack thread for inspection without posting",
      "data": {
        "scenario": {
          "name": "summarize-a-slack-thread-for-inspection-without-posting",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the thread summarization capability and its read-only execution posture.",
            "capability": "slack.thread.summarize",
            "confidence": "high",
            "time_scope": "Current thread context",
            "actor_context": "Slack requester inspecting a thread within an approved channel",
            "business_scope": "Thread inspection and summarization without mutation"
          },
          "category": "safety",
          "narrative": "A Slack requester wants to understand a thread quickly before taking action. The governed service retrieves bounded thread replies for a specific channel and thread and returns summary context without posting anything back to Slack.",
          "expected_behavior": [
            "Require both channel and thread references.",
            "Return summary context for the thread without posting or mutating Slack.",
            "Keep the result bounded to the requested thread.",
            "Deny attempts to turn the summary flow into raw workspace access."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Expose thread summarization as a read-only governed capability.",
            "Make no-posting behavior explicit in the runtime contract.",
            "Support audit evidence that the flow remained inspection-only."
          ],
          "participating_services": [
            "slack-fronting"
          ]
        }
      }
    },
    {
      "id": "scn-7dc99414-a444-4e38-a6d9-90d0aad73f13",
      "title": "Prepare a Slack channel message preview before any send action",
      "data": {
        "scenario": {
          "name": "prepare-a-slack-channel-message-preview-before-any-send-action",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "Directly supported by the prepare-channel-message capability, prepare-only posture, and grant policy for one-time or session-bound preparation.",
            "capability": "slack.message.prepare",
            "confidence": "high",
            "time_scope": "Single message preparation session",
            "actor_context": "Slack requester allowed to draft within governed channel boundaries",
            "business_scope": "Governed message drafting with preview-only behavior and no direct posting"
          },
          "category": "cross_service",
          "narrative": "A Slack requester wants to communicate in a channel but must do so through governed preparation. The service accepts the target channel and message text, produces a preview, and stops before any message is posted.",
          "expected_behavior": [
            "Produce a preview instead of sending a message.",
            "Respect channel boundaries before preparing content.",
            "Make the stop-before-send boundary explicit to the requester.",
            "Avoid any raw Slack posting path."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Model preview-only message preparation as a first-class capability.",
            "Represent approval or later execution as a separate governed step, not an implicit side effect.",
            "Capture audit evidence for who prepared what and for which channel."
          ],
          "participating_services": [
            "slack-fronting"
          ]
        }
      }
    }
  ],
  "service_design": {
    "id": "shape-51152c42-a608-4d24-93e8-127cd0999f38",
    "title": "Assistant-Drafted Service Shape",
    "data": {
      "shape": {
        "id": "shape-3c0d0b1a-798e-4531-a4ff-ed6c7b9bb1df",
        "name": "Slack Fronting Showcase 0.2.0 RC4",
        "type": "multi_service",
        "notes": [
          "Assistant-derived first pass. Review service boundaries before locking Developer Design.",
