        "services": [
          {
            "id": "slack-fronting",
            "name": "Slack Fronting",
            "role": "implementation service",
            "capabilities": [
              "slack.channel.read_context",
              "slack.thread.summarize",
              "slack.message.prepare",
              "slack.incident_update.prepare"
            ],
            "owns_concepts": [],
            "responsibilities": [
              "Own a reviewed portion of the bounded workflow, policy checks, clarification stops, and governed response contract."
